import java.util.ArrayList;import java.util.List;import java.util.Map;
final class CircuitBreakerPattern{static final class Breaker{final int threshold,cooldown;int failures,now,openedAt,forwarded;String state="closed";Breaker(int t,int c){threshold=t;cooldown=c;}String call(String result){if(state.equals("open")){if(now-openedAt<cooldown)return"rejected";state="half_open";}forwarded++;if(state.equals("half_open")){if(result.equals("success")){state="closed";failures=0;return"probe_success";}state="open";openedAt=now;return"probe_failed";}if(result.equals("success")){failures=0;return"success";}failures++;if(failures>=threshold){state="open";openedAt=now;return"opened";}return"failure";}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Breaker b=new Breaker(((Number)input.get("threshold")).intValue(),((Number)input.get("cooldown")).intValue());List<String>out=new ArrayList<>();for(Map<String,Object>event:(List<Map<String,Object>>)input.getOrDefault("events",List.of())){if(event.containsKey("advance")){b.now+=((Number)event.get("advance")).intValue();out.add("advanced");}else out.add(b.call(String.valueOf(event.get("result"))));}return Map.of("decisions",out,"final",b.state,"forwarded",b.forwarded);}}
